#include<bits/stdc++.h>
#define int long long
using namespace std;
const int MAXN = 5e5 + 10;
const int inf = -0x888;
int n, d, k;
int s[MAXN], x[MAXN];
int dp[MAXN];
bool check(int mid){
	for(int i = 0; i < MAXN; i++) dp[i] = inf;
	deque<int>q;
	dp[0] = 0;
	int mini = max(1ll, d - mid), maxx = d + mid;
	int l = 0;
	for(int r = 1; r <= n; r++){
		while(s[r] - s[l] >= mini){//如果单调队列太长了，弹出 
			if(dp[l] != inf){
				while(q.size() && dp[q.back()] <= dp[l])q.pop_back();
				q.push_back(l);
			}
			l++;
		}
		while(q.size() && s[r] - s[q.front()] > maxx)q.pop_front();
		if(q.size())dp[r] = x[r] + dp[q.front()];
		if(dp[r] >= k)return true;
	}
	return false;
}
signed main()
{
	cin >> n >> d >> k;
	for(int i = 1; i <= n; i++)cin >> s[i] >> x[i];
	int l = 0, r = 1e9 + 10;
	while(l < r){
		int mid = (l + r) >> 1;
		if(check(mid))r = mid;
		else l = mid + 1;
	}
	if(l == -1e9 + 10)return cout << -1, 0;
	cout << r;
}
